def conv2d_params(C_in: int, C_out: int, kH: int, kW: int,
                  bias: bool = True) -> int:
    return C_out * (C_in * kH * kW + int(bias))

def batchnorm_params(C: int) -> int:
    return 2 * C

def linear_params(in_features: int, out_features: int,
                  bias: bool = True) -> int:
    return in_features * out_features + int(bias) * out_features

def count_model_params(layers: list) -> int:
    total = 0
    for layer in layers:
        t = layer['type']
        if t == 'conv2d':
            total += conv2d_params(layer['C_in'], layer['C_out'],
                                    layer['kH'], layer['kW'],
                                    layer.get('bias', True))
        elif t == 'batchnorm':
            total += batchnorm_params(layer['C'])
        elif t == 'linear':
            total += linear_params(layer['in_features'], layer['out_features'],
                                    layer.get('bias', True))
        elif t == 'depthwise_conv':
            C = layer['C']
            total += conv2d_params(1, C, layer['kH'], layer['kW'],
                                    layer.get('bias', True))
    return total
